<?php
if (!defined('ABSPATH')) { exit; }
class IMSDA_Reg_Dispatcher {
    public static function send($queue_item){ $event=IMSDA_Reg_Event_Registry::get($queue_item['event_slug']); if(!$event) return 'Event not found'; $parsed=IMSDA_Reg_Parser::parse($queue_item['entry_id'],$event); if(empty($parsed)) return 'Submission not found'; $payload=array_merge($parsed,['action'=>$queue_item['action'],'secret'=>$event->gas_secret,'site'=>site_url(),'version'=>IMSDA_REG_VERSION,'edit_page_url'=>$event->edit_page_url]); $res=wp_remote_post($event->gas_url,['timeout'=>45,'headers'=>['Content-Type'=>'application/json'],'body'=>wp_json_encode($payload)]); if(is_wp_error($res)) return $res->get_error_message(); $code=wp_remote_retrieve_response_code($res); if($code!==200) return 'HTTP '.$code.' from GAS'; $body=json_decode(wp_remote_retrieve_body($res),true); if(!is_array($body)) return 'Invalid GAS response'; if(empty($body['success'])){ if(($queue_item['action']==='register') && !empty($body['capacityFull'])){ $queue_item['action']='waitlist'; $r=self::send($queue_item); if($r===true){ IMSDA_Reg_Event_Registry::increment_counter($event->slug,'waitlist'); return true; } return $r; } return $body['message'] ?? 'GAS error'; }
    if(empty($body['duplicate'])){ if($queue_item['action']==='register') IMSDA_Reg_Event_Registry::increment_counter($event->slug,'registered'); if($queue_item['action']==='waitlist') IMSDA_Reg_Event_Registry::increment_counter($event->slug,'waitlist'); }
    return true; }
    public static function gas_request($event_slug,$payload,$timeout=30){ $event=IMSDA_Reg_Event_Registry::get($event_slug); if(!$event) return ['success'=>false,'message'=>'Event not found']; $payload=array_merge($payload,['secret'=>$event->gas_secret,'site'=>site_url(),'edit_page_url'=>$event->edit_page_url]); $res=wp_remote_post($event->gas_url,['timeout'=>intval($timeout),'headers'=>['Content-Type'=>'application/json'],'body'=>wp_json_encode($payload)]); if(is_wp_error($res)) return ['success'=>false,'message'=>$res->get_error_message()]; $body=json_decode(wp_remote_retrieve_body($res),true); return is_array($body) ? $body : ['success'=>false,'message'=>'Invalid response']; }
}
